import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import AdminMentorLayout from '../components/AdminMentorLayout.jsx';
import { ErrorState, LoadingState } from '../components/LoadingState.jsx';
import MetricCard from '../components/MetricCard.jsx';
import StatusBadge from '../components/StatusBadge.jsx';
import { adminMentorApi } from '../services/api.js';
import { formatDateTime } from '../utils/formatters.js';

export default function MentorDashboardPage() {
  const [dashboard, setDashboard] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    let mounted = true;

    adminMentorApi
      .getMentorDashboard()
      .then((response) => {
        if (mounted) {
          setDashboard(response.data);
          setError('');
        }
      })
      .catch((requestError) => {
        if (mounted) {
          setError(requestError.message);
        }
      })
      .finally(() => {
        if (mounted) {
          setLoading(false);
        }
      });

    return () => {
      mounted = false;
    };
  }, []);

  return (
    <AdminMentorLayout
      area="mentor"
      title="Mentor Dashboard"
      subtitle="Theo doi course assignment, hang doi cham bai va review gan day."
    >
      {loading ? <LoadingState message="Dang tai dashboard mentor..." /> : null}
      {!loading && error ? <ErrorState message={error} /> : null}

      {!loading && dashboard ? (
        <div className="d-grid gap-4">
          <div className="row g-3">
            <div className="col-12 col-md-6 col-xl-3">
              <MetricCard
                helper="Course dang duoc phan cong"
                label="Assignments"
                tone="primary"
                value={dashboard.summary.activeAssignments}
              />
            </div>
            <div className="col-12 col-md-6 col-xl-3">
              <MetricCard
                helper="Submission can xu ly"
                label="Pending reviews"
                tone="warning"
                value={dashboard.summary.pendingReviews}
              />
            </div>
            <div className="col-12 col-md-6 col-xl-3">
              <MetricCard
                helper={`${dashboard.summary.passReviews} PASS`}
                label="Completed"
                tone="success"
                value={dashboard.summary.completedReviews}
              />
            </div>
            <div className="col-12 col-md-6 col-xl-3">
              <MetricCard
                helper="Can learner nop lai"
                label="Fail reviews"
                tone="danger"
                value={dashboard.summary.failReviews}
              />
            </div>
          </div>

          <div className="row g-4">
            <div className="col-12 col-xl-5">
              <div className="card admin-mentor-card h-100">
                <div className="card-header bg-white">
                  <h2 className="h5 mb-0">Active assignments</h2>
                </div>
                <div className="list-group list-group-flush">
                  {dashboard.assignments.map((assignment) => (
                    <div className="list-group-item" key={assignment.id}>
                      <div className="d-flex justify-content-between gap-3">
                        <div>
                          <strong className="d-block">{assignment.courseTitle}</strong>
                          <span className="small text-secondary">
                            Assigned {formatDateTime(assignment.assignedAt)}
                          </span>
                        </div>
                        <StatusBadge status={assignment.status} />
                      </div>
                      <div className="mt-2 small text-secondary">
                        {assignment.pendingSubmissions} pending submissions
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="col-12 col-xl-7">
              <div className="card admin-mentor-card h-100">
                <div className="card-header bg-white d-flex justify-content-between align-items-center">
                  <h2 className="h5 mb-0">Next submissions</h2>
                  <Link className="btn btn-sm btn-outline-primary" to="/mentor/review-queue">
                    Open queue
                  </Link>
                </div>
                <div className="table-responsive">
                  <table className="table table-hover align-middle mb-0 admin-mentor-table">
                    <thead className="table-light">
                      <tr>
                        <th>Learner</th>
                        <th>Course</th>
                        <th>Submitted</th>
                        <th>Status</th>
                        <th className="text-end">Action</th>
                      </tr>
                    </thead>
                    <tbody>
                      {dashboard.queue.map((submission) => (
                        <tr key={submission.id}>
                          <td>
                            <strong className="d-block">{submission.learnerName}</strong>
                            <span className="small text-secondary">{submission.learnerEmail}</span>
                          </td>
                          <td>{submission.courseTitle}</td>
                          <td>{formatDateTime(submission.submittedAt)}</td>
                          <td>
                            <StatusBadge status={submission.status} />
                          </td>
                          <td className="text-end">
                            <Link className="btn btn-sm btn-primary" to={`/mentor/reviews/${submission.id}`}>
                              Review
                            </Link>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>

          <div className="card admin-mentor-card">
            <div className="card-header bg-white">
              <h2 className="h5 mb-0">Recent review results</h2>
            </div>
            <div className="table-responsive">
              <table className="table table-hover align-middle mb-0 admin-mentor-table">
                <thead className="table-light">
                  <tr>
                    <th>Learner</th>
                    <th>Course</th>
                    <th>Result</th>
                    <th>Reviewed at</th>
                    <th>Feedback</th>
                  </tr>
                </thead>
                <tbody>
                  {dashboard.reviews.map((review) => (
                    <tr key={review.id}>
                      <td>{review.learnerName}</td>
                      <td>{review.courseTitle}</td>
                      <td>
                        <StatusBadge status={review.result} />
                      </td>
                      <td>{formatDateTime(review.reviewedAt)}</td>
                      <td className="text-secondary small">{review.feedback}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      ) : null}
    </AdminMentorLayout>
  );
}
